extern char *str_dup(const char *s);
if (!data) return str_dup("");
size_t n = strlen(data);
char *out = (char *)malloc(n * 2 + 1);
if (!out) return NULL;
static const char *hex = "0123456789ABCDEF";
for (size_t i = 0; i < n; i++) {
    unsigned char b = (unsigned char)data[i];
    out[i * 2] = hex[b >> 4];
    out[i * 2 + 1] = hex[b & 15];
}
out[n * 2] = '\0';
return out;
